class LUPrefix {
public:
    LUPrefix(int n) : maxPrefix(0), nextVideo(1) {
        videos = vector<bool>(n + 1, false);
    }

    void upload(int video) {
        videos[video] = true;
        while (videos[nextVideo]) {
            maxPrefix = nextVideo;
            nextVideo++;
        }
    }

    int longest() {
        return maxPrefix;
    }
private:
    int maxPrefix;
    int nextVideo;
    vector<bool> videos;
};
```
